-
-    isAvailable() { return this.available; }
-
-    /**
-     * Group rows by key and return group assignments.
-     * @param {Uint32Array} keys - Hash keys for each row
-     * @returns {Promise<{groupIds: Uint32Array, numGroups: number}>}
