-    async groupBy(keys) {
-        const size = keys.length;
-
-        if (!this.available || size < GPU_GROUP_THRESHOLD) {
-            return this._cpuGroupBy(keys);
-        }
-
-        // Hash table capacity (power of 2, at least 2x estimated groups)
